import app from 'flarum/admin/app';
import FramioSettingsPage from './components/FramioSettingsPage';

app.initializers.add('framio-social-share', () => {
  // 1. Eklentiyi ve Ayar Sayfasını Kaydet
  app.extensionData
    .for('framio-social-share')
    .registerPage(FramioSettingsPage) // Özel sayfamızı kullan
    .registerPermission(
      {
        icon: 'fab fa-facebook',
        label: 'Sosyal Medyada Paylaşabilir',
        permission: 'framio.social-share.use',
      },
      'start'
    );
});